// Get inputs
const orders = $input.all(0).map(i => i.json);
const refundsRaw = $input.all(1).map(i => i.json);

// --------------------
// 1. SALES KPIs
// --------------------
let totalSalesAmount = 0;
let totalOrderCount = orders.length;

for (const order of orders) {
  totalSalesAmount += Number(order.order_total || 0);
}

// --------------------
// 2. REFUND KPIs (Deduplicate)
// --------------------
const refundMap = new Map();

for (const refund of refundsRaw) {
  if (!refundMap.has(refund.refund_id)) {
    refundMap.set(refund.refund_id, refund);
  }
}

const refunds = Array.from(refundMap.values());

let totalRefundAmount = 0;
let totalRefundCount = refunds.length;

for (const refund of refunds) {
  totalRefundAmount += Number(refund.refund_amount || 0);
}

// --------------------
// 3. RATIOS (Safe Divide)
// --------------------
const refundRatioAmount =
  totalSalesAmount > 0
    ? ((totalRefundAmount / totalSalesAmount) * 100).toFixed(2)
    : 0;

const refundRatioCount =
  totalOrderCount > 0
    ? ((totalRefundCount / totalOrderCount) * 100).toFixed(2)
    : 0;

// --------------------
// 4. FLAGS / RISK INDICATORS
// --------------------
const flags = [];

if (refundRatioAmount > 10) {
  flags.push("High refund ratio (>10%)");
}

if (totalRefundAmount > totalSalesAmount) {
  flags.push("Refund amount exceeds sales");
}

if (totalSalesAmount === 0 && totalRefundAmount > 0) {
  flags.push("Refunds exist with zero sales");
}

// --------------------
// 5. CFO SUMMARY OBJECT
// --------------------
return [
  {
    json: {
      total_sales_amount: totalSalesAmount,
      total_order_count: totalOrderCount,
      total_refund_amount: totalRefundAmount,
      total_refund_count: totalRefundCount,
      refund_ratio_amount_pct: refundRatioAmount,
      refund_ratio_count_pct: refundRatioCount,
      flags,
      period_generated_at: new Date().toISOString()
    }
  }
];

